import json, sys, glob
data = json.load(sys.stdin)
# Handle manifest (chunked files)
if 'part_files' in data:
    candidates = []
    for pf in data['part_files']:
        with open(pf) as f:
            part = json.load(f)
            for key in ['deadCodeCandidates', 'candidates', 'items']:
                if key in part:
                    candidates.extend(part[key])
                    break
else:
    for key in ['deadCodeCandidates', 'candidates', 'items']:
        if key in data:
            candidates = data[key]
            break
    else:
        candidates = []
dead_code = []
for c in candidates:
    dead_code.append({
        'file': c.get('file', ''),
        'name': c.get('name', ''),
        'type': c.get('type', 'function')
    })
print(json.dumps({'dead_code': dead_code, 'analysis_complete': True}, indent=2))
" > REPORT.json
